import React from 'react';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Container from '@mui/material/Container';
import FormControl from '@mui/material/FormControl';
import InputLabel from '@mui/material/InputLabel';
import MenuItem from '@mui/material/MenuItem';
import Pagination from '@mui/material/Pagination';
import Select from '@mui/material/Select';
import Stack from '@mui/material/Stack';
import Switch from '@mui/material/Switch';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';
import { Link } from 'react-router-dom';

import DataTable, { Column } from '../components/common/DataTable';
import UserAlert from '../components/common/UserAlert';
import { api } from '../services/api';
import type { Category, Network } from '../types/entities';
import { Status } from '../types/entities';
import { useAppDispatch } from '../store/hooks';
import { showSnackbar } from '../store/slices/uiSlice';

type Row = {
  id: number;
  title: string;
  status: string;
  featured: string;
  networkId: number;
  categories: string;
};

const columns: Column<Row>[] = [
  { key: 'id', header: 'ID', render: (r) => r.id },
  { key: 'title', header: 'Titre', render: (r) => r.title },
  { key: 'status', header: 'Status', render: (r) => r.status },
  { key: 'featured', header: 'Featured', render: (r) => r.featured },
  { key: 'networkId', header: 'Network', render: (r) => r.networkId },
  { key: 'categories', header: 'Categories', render: (r) => r.categories },
];

export default function ArticlesList() {
  const dispatch = useAppDispatch();
  const [query, setQuery] = React.useState('');
  const [status, setStatus] = React.useState<'draft' | 'published' | 'archived' | ''>('');
  const [featured, setFeatured] = React.useState<boolean | undefined>(undefined);
  const [networkId, setNetworkId] = React.useState<number | ''>('');
  const [categoryIds, setCategoryIds] = React.useState<number[]>([]);

  const [sort, setSort] = React.useState<'publishedAt' | 'title' | 'createdAt'>('publishedAt');
  const [order, setOrder] = React.useState<'asc' | 'desc'>('desc');
  const [page, setPage] = React.useState(1);
  const [pageSize, setPageSize] = React.useState(10);

  const [categories, setCategories] = React.useState<Category[]>([]);
  const [networks, setNetworks] = React.useState<Network[]>([]);

  const [rows, setRows] = React.useState<Row[]>([]);
  const [total, setTotal] = React.useState(0);
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);

  const refreshList = React.useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const data = await api.listArticles({
        query: query || undefined,
        status: status || undefined,
        featured,
        networkId: networkId === '' ? undefined : networkId,
        categoryIds: categoryIds.length ? categoryIds : undefined,
        sort,
        order,
        page,
        pageSize,
      });

      setTotal(data.total);
      setRows(
        data.items.map((a) => {
          const catNames = a.categoryIds
            .map((id) => categories.find((c) => c.id === id)?.name)
            .filter((v): v is string => Boolean(v));

          return {
            id: a.id,
            title: a.title,
            status: a.status,
            featured: a.featured ? 'yes' : 'no',
            networkId: a.networkId,
            categories: catNames.join(', '),
          };
        })
      );
    } catch {
      setError('Impossible de charger les articles.');
      dispatch(showSnackbar({ severity: 'error', message: 'Impossible de charger les articles.' }));
    } finally {
      setLoading(false);
    }
  }, [query, status, featured, networkId, categoryIds, sort, order, page, pageSize, categories, dispatch]);

  React.useEffect(() => {
    let mounted = true;

    Promise.all([api.listCategories(), api.listNetworks()])
      .then(([cats, nets]) => {
        if (!mounted) return;
        setCategories(cats);
        setNetworks(nets);
      })
      .catch(() => {
        if (!mounted) return;
        setError('Impossible de charger les filtres (catégories/réseaux).');
        dispatch(showSnackbar({ severity: 'error', message: 'Impossible de charger les filtres.' }));
      });

    return () => {
      mounted = false;
    };
  }, [dispatch]);

  React.useEffect(() => {
    void refreshList();
  }, [refreshList]);

  const patchStatus = async (id: number, nextStatus: 'draft' | 'published' | 'archived') => {
    try {
      await api.patchArticleStatus(id, nextStatus);
      dispatch(showSnackbar({ severity: 'success', message: `Status mis à jour (${nextStatus}).` }));
      await refreshList();
    } catch (e) {
      const msg = e instanceof Error ? e.message : '';
      if (msg.includes('403')) {
        dispatch(showSnackbar({ severity: 'error', message: 'Accès refusé.' }));
      } else {
        dispatch(showSnackbar({ severity: 'error', message: 'Impossible de changer le status.' }));
      }
    }
  };

  const toggleFeatured = async (id: number) => {
    try {
      const a = await api.getArticle(id);
      await api.updateArticle(id, { featured: !a.featured });
      dispatch(showSnackbar({ severity: 'success', message: `Featured: ${!a.featured ? 'activé' : 'désactivé'}.` }));
      await refreshList();
    } catch {
      dispatch(showSnackbar({ severity: 'error', message: 'Impossible de changer featured.' }));
    }
  };

  const removeArticle = async (id: number) => {
    const ok = window.confirm(`Supprimer l'article #${id} ?`);
    if (!ok) return;

    try {
      await api.deleteArticle(id);
      dispatch(showSnackbar({ severity: 'success', message: 'Article supprimé.' }));
      await refreshList();
    } catch (e) {
      const msg = e instanceof Error ? e.message : '';
      if (msg.includes('403')) {
        dispatch(showSnackbar({ severity: 'error', message: 'Accès refusé (admin requis).' }));
      } else {
        dispatch(showSnackbar({ severity: 'error', message: 'Impossible de supprimer.' }));
      }
    }
  };

  const columnsWithActions: Column<Row>[] = [
    ...columns,
    {
      key: 'actions',
      header: 'Actions',
      render: (r) => (
        <Stack direction="row" spacing={1}>
          <Button aria-label={`Edit article ${r.id}`} component={Link} to={`/articles/${r.id}/edit`} size="small">
            Edit
          </Button>
          <Button
            aria-label={`Toggle featured article ${r.id}`}
            size="small"
            onClick={() => {
              void toggleFeatured(r.id);
            }}
          >
            Featured
          </Button>
          {r.status === Status.ARCHIVED ? (
            <Button
              aria-label={`Unarchive article ${r.id}`}
              size="small"
              onClick={() => {
                void patchStatus(r.id, Status.DRAFT);
              }}
            >
              Unarchive
            </Button>
          ) : (
            <Button
              aria-label={`Archive article ${r.id}`}
              size="small"
              onClick={() => {
                void patchStatus(r.id, Status.ARCHIVED);
              }}
            >
              Archive
            </Button>
          )}
          <Button
            aria-label={`Delete article ${r.id}`}
            size="small"
            color="error"
            onClick={() => {
              void removeArticle(r.id);
            }}
          >
            Delete
          </Button>
        </Stack>
      ),
    },
  ];

  const pageCount = Math.max(1, Math.ceil(total / pageSize));

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        <Stack direction="row" alignItems="center" spacing={2}>
          <Typography variant="h5" sx={{ flexGrow: 1 }}>
            Articles
          </Typography>
          <Button aria-label="Créer un article" variant="contained" component={Link} to="/articles/new">
            Créer
          </Button>
        </Stack>
        {error ? <UserAlert severity="error" message={error} /> : null}

        <Stack direction={{ xs: 'column', md: 'row' }} spacing={2}>
          <TextField
            label="Recherche"
            value={query}
            onChange={(e) => {
              setQuery(e.target.value);
              setPage(1);
            }}
            size="small"
            fullWidth
          />

          <FormControl size="small" sx={{ minWidth: 160 }}>
            <InputLabel id="status-label">Status</InputLabel>
            <Select
              labelId="status-label"
              label="Status"
              value={status}
              onChange={(e) => {
                setStatus(e.target.value as any);
                setPage(1);
              }}
            >
              <MenuItem value="">Tous</MenuItem>
              <MenuItem value={Status.DRAFT}>draft</MenuItem>
              <MenuItem value={Status.PUBLISHED}>published</MenuItem>
              <MenuItem value={Status.ARCHIVED}>archived</MenuItem>
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 180 }}>
            <InputLabel id="network-label">Réseau</InputLabel>
            <Select
              labelId="network-label"
              label="Réseau"
              value={networkId}
              onChange={(e) => {
                const v = String(e.target.value);
                setNetworkId(v === '' ? '' : Number(v));
                setPage(1);
              }}
            >
              <MenuItem value="">Tous</MenuItem>
              {networks.map((n) => (
                <MenuItem key={n.id} value={n.id}>
                  {n.name}
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 220 }}>
            <InputLabel id="categories-label">Catégories</InputLabel>
            <Select
              labelId="categories-label"
              label="Catégories"
              multiple
              value={categoryIds as any}
              onChange={(e) => {
                const v = e.target.value as number[];
                setCategoryIds(v);
                setPage(1);
              }}
            >
              {categories.map((c) => (
                <MenuItem key={c.id} value={c.id}>
                  {c.name}
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <Stack direction="row" spacing={1} alignItems="center" sx={{ pl: { md: 1 } }}>
            <Typography variant="body2">Featured</Typography>
            <Switch
              checked={featured === true}
              onChange={(e) => {
                setFeatured(e.target.checked ? true : undefined);
                setPage(1);
              }}
            />
          </Stack>
        </Stack>

        <Stack direction={{ xs: 'column', md: 'row' }} spacing={2} alignItems={{ md: 'center' }}>
          <FormControl size="small" sx={{ minWidth: 160 }}>
            <InputLabel id="sort-label">Tri</InputLabel>
            <Select
              labelId="sort-label"
              label="Tri"
              value={sort}
              onChange={(e) => {
                setSort(e.target.value as any);
                setPage(1);
              }}
            >
              <MenuItem value="publishedAt">publishedAt</MenuItem>
              <MenuItem value="title">title</MenuItem>
              <MenuItem value="createdAt">createdAt</MenuItem>
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 140 }}>
            <InputLabel id="order-label">Ordre</InputLabel>
            <Select
              labelId="order-label"
              label="Ordre"
              value={order}
              onChange={(e) => {
                setOrder(e.target.value as any);
                setPage(1);
              }}
            >
              <MenuItem value="desc">desc</MenuItem>
              <MenuItem value="asc">asc</MenuItem>
            </Select>
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 140 }}>
            <InputLabel id="pageSize-label">Page size</InputLabel>
            <Select
              labelId="pageSize-label"
              label="Page size"
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value));
                setPage(1);
              }}
            >
              <MenuItem value={5}>5</MenuItem>
              <MenuItem value={10}>10</MenuItem>
              <MenuItem value={20}>20</MenuItem>
            </Select>
          </FormControl>

          <Box sx={{ flexGrow: 1 }} />
          <Typography variant="body2">
            {loading ? 'Chargement...' : `${total} résultat(s)`}
          </Typography>
        </Stack>

        <DataTable columns={columnsWithActions} rows={rows} />

        <Stack direction="row" justifyContent="center">
          <Pagination
            count={pageCount}
            page={page}
            onChange={(_, p) => setPage(p)}
            color="primary"
          />
        </Stack>
      </Stack>
    </Container>
  );
}
